package format

import (
	"strings"
	"testing"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
	"github.com/hashicorp/terraform/internal/states"
)

func TestCompactDiffFormatter_Format(t *testing.T) {
	tests := map[string]struct {
		plan *plans.Plan
		want string
	}{
		"empty plan": {
			plan: &plans.Plan{
				Changes: plans.NewChangesSrc(),
			},
			want: "",
		},
		"single create": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: addrs.NoKey,
								},
							},
							DeposedKey: states.NotDeposed,
							Action:     plans.Create,
						},
					},
				},
			},
			want: strings.Join([]string{
				"# Create:",
				"  + aws_instance.example",
				"",
				"Plan: 1 to add",
				"",
			}, "\n"),
		},
		"multiple creates": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "web",
									},
									Key: addrs.NoKey,
								},
							},
							DeposedKey: states.NotDeposed,
							Action:     plans.Create,
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_security_group",
										Name: "default",
									},
									Key: addrs.NoKey,
								},
							},
							DeposedKey: states.NotDeposed,
							Action:     plans.Create,
						},
					},
				},
			},
			want: strings.Join([]string{
				"# Create:",
				"  + aws_instance.web",
				"  + aws_security_group.default",
				"",
				"Plan: 2 to add",
				"",
			}, "\n"),
		},
		"mixed changes": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "new",
									},
									Key: addrs.NoKey,
								},
							},
							DeposedKey: states.NotDeposed,
							Action:     plans.Create,
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "old",
									},
									Key: addrs.NoKey,
								},
							},
							DeposedKey: states.NotDeposed,
							Action:     plans.Delete,
						},
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_security_group",
										Name: "default",
									},
									Key: addrs.NoKey,
								},
							},
							DeposedKey: states.NotDeposed,
							Action:     plans.Update,
						},
					},
				},
			},
			want: strings.Join([]string{
				"# Create:",
				"  + aws_instance.new",
				"",
				"# Update:",
				"  ~ aws_security_group.default",
				"",
				"# Delete:",
				"  - aws_instance.old",
				"",
				"Plan: 1 to add, 1 to change, 1 to delete",
				"",
			}, "\n"),
		},
		"replace action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: addrs.NoKey,
								},
							},
							DeposedKey: states.NotDeposed,
							Action:     plans.DeleteThenCreate,
						},
					},
				},
			},
			want: strings.Join([]string{
				"# Replace (delete then create):",
				"  ± aws_instance.example",
				"",
				"Plan: 1 to replace",
				"",
			}, "\n"),
		},
		"no deposed keys": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "example",
									},
									Key: addrs.NoKey,
								},
							},
							DeposedKey: states.NotDeposed,
							Action:     plans.Update,
						},
						// This one should be filtered out because DeposedKey is set
						{
							Addr: addrs.AbsResourceInstance{
								Module: addrs.RootModuleInstance,
								Resource: addrs.ResourceInstance{
									Resource: addrs.Resource{
										Mode: addrs.ManagedResourceMode,
										Type: "aws_instance",
										Name: "deposed",
									},
									Key: addrs.NoKey,
								},
							},
							DeposedKey: "deposed-key",
							Action:     plans.Delete,
						},
					},
				},
			},
			want: strings.Join([]string{
				"# Update:",
				"  ~ aws_instance.example",
				"",
				"Plan: 1 to change",
				"",
			}, "\n"),
		},
		"nil plan": {
			plan: nil,
			want: "",
		},
		"nil changes": {
			plan: &plans.Plan{
				Changes: nil,
			},
			want: "",
		},
	}

	formatter := &CompactDiffFormatter{}

	for name, test := range tests {
		t.Run(name, func(t *testing.T) {
			got := formatter.Format(test.plan, nil)
			if got != test.want {
				t.Errorf("wrong output\ngot:\n%q\n\nwant:\n%q", got, test.want)
			}
		})
	}
}

func TestCompactDiffFormatter_FormatComplex(t *testing.T) {
	// Test a more complex scenario with module resources
	formatter := &CompactDiffFormatter{}

	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "web",
							},
							Key: addrs.IntKey(0),
						},
					},
					DeposedKey: states.NotDeposed,
					Action:     plans.Create,
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "web",
							},
							Key: addrs.IntKey(1),
						},
					},
					DeposedKey: states.NotDeposed,
					Action:     plans.Create,
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_security_group",
								Name: "default",
							},
							Key: addrs.NoKey,
						},
					},
					DeposedKey: states.NotDeposed,
					Action:     plans.Create,
				},
			},
		},
	}

	output := formatter.Format(plan, nil)

	// Check that output contains expected elements
	if !strings.Contains(output, "# Create:") {
		t.Error("output should contain Create section header")
	}
	if !strings.Contains(output, "aws_instance.web[0]") {
		t.Error("output should contain aws_instance.web[0]")
	}
	if !strings.Contains(output, "aws_instance.web[1]") {
		t.Error("output should contain aws_instance.web[1]")
	}
	if !strings.Contains(output, "aws_security_group.default") {
		t.Error("output should contain aws_security_group.default")
	}
	if !strings.Contains(output, "Plan: 3 to add") {
		t.Error("output should contain summary with 3 to add")
	}
}

func TestActionSymbolCompact(t *testing.T) {
	tests := map[plans.Action]string{
		plans.Create:           "+",
		plans.Update:           "~",
		plans.Delete:           "-",
		plans.DeleteThenCreate: "±",
		plans.CreateThenDelete: "∓",
		plans.CreateThenForget: "⨥",
		plans.Forget:           ".",
		plans.Read:             "<=",
		plans.NoOp:             " ",
	}

	for action, expectedSymbol := range tests {
		t.Run(action.String(), func(t *testing.T) {
			got := actionSymbolCompact(action)
			if got != expectedSymbol {
				t.Errorf("wrong symbol for %s\ngot: %q\nwant: %q", action.String(), got, expectedSymbol)
			}
		})
	}
}

