	case plans.DeleteThenCreate:
		return "±"
	case plans.CreateThenDelete:
		return "∓"
	case plans.CreateThenForget:
		return "⨥"
	case plans.Forget:
		return "."
	case plans.Read:
		return "<="
	case plans.NoOp:
		return " "
	default:
		return "?"
	}
